import{_ as e,o as a,c as o,j as t,a as u,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const c=JSON.parse('{"title":"真相","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/远程武器/1.D级/真相.md","filePath":"4.资源分区/7.物品与装备/2.武器/远程武器/1.D级/真相.md"}'),s={name:"4.资源分区/7.物品与装备/2.武器/远程武器/1.D级/真相.md"};function d(b,r,q,p,l,i){return a(),o("div",null,[...r[0]||(r[0]=[t("h1",{id:"真相",tabindex:"-1"},[u("真相 "),t("a",{class:"header-anchor",href:"#真相","aria-label":'Permalink to "真相"'},"​")],-1),t("table",{class:"bannerparthead"},[t("tbody",null,[t("tr",{id:"hdr"},[t("td",{class:"runninghead",nowrap:""},"TMD：新世短歌038")])])],-1),n('<h1 id="真相-1" tabindex="-1">真相 <a class="header-anchor" href="#真相-1" aria-label="Permalink to &quot;真相&quot;">​</a></h1><p>真相<br> 科技本质<br> D+500<br> 描述：<br> &quot;再问你一句，为什么要这么做。&quot;<br> &quot;事到如今，还有这个必要吗？&quot;<br> &quot;……你不该来这里。&quot;<br> &quot;我有我的打算。&quot;<br> &quot;到现在你也不愿意说真话吗？&quot;<br> &quot;你和我一样。&quot;<br> &quot;……&quot;<br> &quot;……&quot;<br> &quot;人说谎言，&quot;<br> &quot;枪说真相。&quot;<br> 砰。</p><p>这是一把银白色枪身，有着牛皮手工握把的左轮手枪，同时只能装填6发子弹，体积3，基础射程30米，武器伤害7L，具有【高速5】的基础特性。<br> 这把枪的左侧枪管上有一行淡淡的英文&quot;TRUTH&quot;<br> 这把武器必须以移动动作上弹，这意味着任何降低装填动作的效果对该武器不起作用。<br> 上弹后的首次瞄准会为该武器额外提供1dp瞄准加值，虽然该武器的装弹量是6枚，但这并没有实际的作用，事实上该武器每次装弹仅能射击一次，这次攻击会具有【9加骰】，每次射击会同时射出5枚子弹，这视为该武器的速射等级为【长点射】，并获得相应的益处。射出的5枚子弹无论装填前形态如何，在射出后子弹的底部会依次写上&quot;T,R,U,T,H&quot;这五个英文单词，枪械中遗留的那枚子弹上会写着&quot;LIE&quot;，若取出这枚固定不会被射出的子弹，该武器的所有特性将不会生效，仅留下基础属性。</p><p>此外，该武器附带左轮手枪专用装弹器，这仍然无法使其降低装填动作。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',6)])])}const h=e(s,[["render",d]]);export{c as __pageData,h as default};
